package Welcome;

public class Substraction {
	int sub(int a, int b) {
		int result = a=b;
		return result;
	}

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Substraction s= new Substraction();
		int result =s.sub(500, 200);
		System.out.println("the subst"+result);

	}

}
